import React, { useState } from "react";
import { useProtocols } from "../hooks/useprotocols";
import MqttForm from "./MqttForm";

const ConnectionModal = ({ onClose, sensors }) => {
  const { protocols, loading, error } = useProtocols();
  const [selectedProtocol, setSelectedProtocol] = useState("");

  const protocolKey = selectedProtocol?.toUpperCase(); // ✅ FIX

  return (
    <div
      className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center"
      style={{ backgroundColor: "rgba(0,0,0,0.6)", zIndex: 1050 }}
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div className="card border-0 shadow-lg p-4" style={{ width: "520px" }}>
        <div className="d-flex justify-content-between mb-3">
          <h5>Connection Setup</h5>
          <button className="btn-close" onClick={onClose}></button>
        </div>

        {/* ✅ SAME DROPDOWN */}
        <label className="sb-form-label mb-2">Select Protocol</label>
        <select
          className="form-select sb-input mb-3"
          value={selectedProtocol}
          onChange={(e) => setSelectedProtocol(e.target.value)}
        >
          <option value="">-- Select Protocol --</option>
          {!loading &&
            protocols.map((p, i) => (
              <option key={i} value={p}>
                {p}
              </option>
            ))}
        </select>

        {/* ✅ MQTT FORM (NOW SHOWS) */}
        {protocolKey === "MQTT" && (
          <MqttForm
            onClose={onClose}
            onConnected={onClose}
          />
        )}
      </div>
    </div>
  );
};

export default ConnectionModal;
